import React, { useEffect, useState } from 'react';
import {
  CRow,
  CCol,
  CCard,
  CCardHeader,
  CCardBody,
  CForm,
  CFormLabel,
  CFormInput,
  CButton,
} from '@coreui/react';
import i18n from 'src/i18n';
import { generalInfoService } from 'src/services/standardUsers'; // à adapter selon ton arborescence

const GeneralInfoDateView = () => {
  const [info, setInfo] = useState({
    starthour: '',
    endhour: '',
  });
  const [loading, setLoading] = useState(false);

  const fetchGeneralInfo = async () => {
    try {
      const res = await generalInfoService.get();
      setInfo({
        starthour: res?.data?.starthour || '',
        endhour: res?.data?.endhour || '',
      });
    } catch (err) {
      console.error('Failed to fetch general info:', err);
    }
  };

  const handleChange = (e) => {
    setInfo((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSave = async () => {
    try {
      setLoading(true);
      await generalInfoService.update(info);
      setLoading(false);
      alert(i18n.t('updateSuccess'));
    } catch (err) {
      setLoading(false);
      console.error('Failed to update:', err);
    }
  };

  useEffect(() => {
    fetchGeneralInfo();
  }, []);

  return (
    <CCard className="mb-4">
      <CCardHeader>
        <strong>{i18n.t('GeneralDateTitle')}</strong>
      </CCardHeader>
      <CCardBody>
        <CForm>
           
       

          <CRow className="mb-3">
            <CCol md={6}>
              <CFormLabel>{i18n.t('startHourLabel')}</CFormLabel>
              <CFormInput
                type="time"
                name="starthour"
                value={info.starthour}
                onChange={handleChange}
              />
            </CCol>
            <CCol md={6}>
              <CFormLabel>{i18n.t('endHourLabel')}</CFormLabel>
              <CFormInput
                type="time"
                name="endhour"
                value={info.endhour}
                onChange={handleChange}
              />
            </CCol>
          </CRow>

          <CButton color="primary" onClick={handleSave} disabled={loading}>
            {i18n.t('saveButtonLabel')}
          </CButton>
        </CForm>
      </CCardBody>
    </CCard>
  );
};

export default GeneralInfoDateView;
